<script setup>
//This file is generated by Table2API.
//If you met a bug, please tell me, thanks!
//wrx 202200905
import { onMounted, ref } from 'vue';
import PageFrame from '@common/layout/FrameIndi_Classic.vue';
import MainPage from '@common/MainPage.vue';
import Page404 from '@common/ResultPage/Page404.vue';
import { make_icon } from '@utility/NaiveHComponent.js';
import { getSysMenus } from '@request/Menu.js';

//此处引入页面组件
import Auth_assets_Page from '../views_system/Auth_assets/auth_assets_Page.vue';
import Auth_role_Page from '../views_system/Auth_role/auth_role_Page.vue';
import File_record_Page from '../views_system/File_record/file_record_Page.vue';
import Sys_language_Page from '../views_system/Sys_language/sys_language_Page.vue';
import Sys_menu_Page from '../views_system/Sys_menu/sys_menu_Page.vue';
import Sys_tenant_Page from '../views_system/Sys_tenant/sys_tenant_Page.vue';
import Sys_user_Page from '../views_system/Sys_user/sys_user_Page.vue';

import {
    getMenuHome,
    executeMenuIcon,
    executeMenuLabel,
    killMenuChildren,
    searchMenuByKey,
} from '@common/layout/indexFuncModified';
import { useStore } from '../store/totalStore';
import { translate } from '@utility/i18n.js';

const store = useStore(); // 全局参数

const NAMESPACE = import.meta.env.VITE_NAMESPACE;

const PageFrameRef = ref(null);

let initMenuHome = getMenuHome(translate.t('首页'));

const keepAliveArray = ref([]); //用于删除Tab取消菜单的持久化
const menus = ref([]);
const menuKey = ref('Home');
const menuObj = ref(initMenuHome);

onMounted(() => {
    window.addEventListener('hashchange', () => {
        updateMenu(location.hash.substring(1));
        if (PageFrameRef.value) {
            PageFrameRef.value.DoMenuRefresh();
        }
    });
    GetUserMenus();
});

//获取用户及菜单
function GetUserMenus() {
    getSysMenus()
        .then((res) => {
            if (res) {
                let storeData = { userName: res.userName };
                store.save(storeData);
                if (res.status) {
                    menus.value = res.datas;
                    killMenuChildren(menus.value);
                    updateMenu(location.hash.substring(1));
                    if (PageFrameRef.value) {
                        PageFrameRef.value.DoMenuRefresh();
                    }
                } else {
                    window.$message.warning(translate.t(res.msg));
                    setTimeout(() => {
                        window.location = '/' + NAMESPACE + '/login.html';
                    }, 400);
                }
            }
        })
        .catch((e) => {
            console.log('出错了', e);
            setTimeout(() => {
                window.location = '/' + NAMESPACE + '/login.html';
            }, 400);
        });
}
//点选菜单
function menuSelected(key) {
    updateMenu(key);
    window.location.hash = key;
}

//更新menuKey,menuObj
function updateMenu(key) {
    if (key == 'Home' || key == '') {
        menuKey.value = key;
        menuObj.value = initMenuHome;
    } else {
        let tempMenuObj = searchMenuByKey(menus.value, key);
        if (Object.keys(tempMenuObj).length > 0) {
            menuKey.value = key;
            menuObj.value = tempMenuObj;
        } else {
            menuKey.value = '404';
            menuObj.value = {};
        }
    }
}

//通过tab的方式关闭菜单
function menuKilled(key) {
    keepAliveArray.value.push(key);
    setTimeout(() => {
        keepAliveArray.value = [];
    }, 1000);
}

//渲染菜单文字
function renderMenuLabel(val) {
    return executeMenuLabel(translate.t(val.label));
}

//渲染菜单图标
function renderMenuIcon(val) {
    return null;
    //return executeMenuIcon(val);

    //根据需要渲染图标
    //return make_icon(icon);
}
</script>
<template>
    <PageFrame
        ref="PageFrameRef"
        :platformTitle="translate.t(NAMESPACE)"
        :menus="menus"
        :menuSelectObj="menuObj"
        @menuSelected="menuSelected"
        @menuTabKilled="menuKilled"
        :renderMenuIcon="renderMenuIcon"
        :renderMenuLabel="renderMenuLabel"
    >
        <template v-slot:main>
            <!-- keep-alive中不可以有注释，同一条件下只允许有一个dom节点 -->
            <keep-alive :exclude="keepAliveArray">
                <MainPage v-if="menuKey == 'Home' || menuKey == ''" :msg="'Welcome'" />
                <Auth_assets_Page v-else-if="menuKey == 'Auth_assets'" />
                <Auth_role_Page v-else-if="menuKey == 'Auth_role'" />
                <File_record_Page v-else-if="menuKey == 'File_record'" />
                <Sys_language_Page v-else-if="menuKey == 'Sys_language'" />
                <Sys_menu_Page v-else-if="menuKey == 'Sys_menu'" />
                <Sys_tenant_Page v-else-if="menuKey == 'Sys_tenant'" />
                <Sys_user_Page v-else-if="menuKey == 'Sys_user'" />
                <Page404 v-else />
            </keep-alive>
        </template>
    </PageFrame>
</template>
<style></style>
